INSERT INTO `mbti_questions` VALUES (1, 'mbti', '在社交场合中，您通常会：', '[{\"text\": \"认识新朋友，扩大社交圈\", \"value\": \"E\"}, {\"text\": \"与已认识的朋友交流，保持小圈子\", \"value\": \"I\"}]', 'EI', NULL, 1, 1, NULL, 1770881506, 1770881506);
INSERT INTO `mbti_questions` VALUES (2, 'mbti', '您更喜欢：', '[{\"text\": \"在团队中工作，与他人合作\", \"value\": \"E\"}, {\"text\": \"独立工作，自己思考问题\", \"value\": \"I\"}]', 'EI', NULL, 2, 1, NULL, 1770881506, 1770881506);
INSERT INTO `mbti_questions` VALUES (3, 'mbti', '当您需要充电时，您会选择：', '[{\"text\": \"与朋友聚会，参加社交活动\", \"value\": \"E\"}, {\"text\": \"独处，阅读或进行个人爱好\", \"value\": \"I\"}]', 'EI', NULL, 3, 1, NULL, 1770881506, 1770881506);
INSERT INTO `mbti_questions` VALUES (4, 'mbti', '在会议或讨论中，您通常：', '[{\"text\": \"积极发言，边说边思考\", \"value\": \"E\"}, {\"text\": \"先思考，然后再发表意见\", \"value\": \"I\"}]', 'EI', NULL, 4, 1, NULL, 1770881506, 1770881506);
INSERT INTO `mbti_questions` VALUES (5, 'mbti', '您更倾向于：', '[{\"text\": \"认识很多人，建立广泛的社交网络\", \"value\": \"E\"}, {\"text\": \"与少数几个人建立深厚的友谊\", \"value\": \"I\"}]', 'EI', NULL, 5, 1, NULL, 1770881506, 1770881506);
INSERT INTO `mbti_questions` VALUES (6, 'mbti', '在工作环境中，您更喜欢：', '[{\"text\": \"开放的办公空间，可以随时与同事交流\", \"value\": \"E\"}, {\"text\": \"安静的私人空间，可以专注工作\", \"value\": \"I\"}]', 'EI', NULL, 6, 1, NULL, 1770881506, 1770881506);
INSERT INTO `mbti_questions` VALUES (7, 'mbti', '当面对问题时，您更倾向于：', '[{\"text\": \"与他人讨论，获取不同观点\", \"value\": \"E\"}, {\"text\": \"独自思考，寻找解决方案\", \"value\": \"I\"}]', 'EI', NULL, 7, 1, NULL, 1770881506, 1770881506);
