INSERT INTO `mbti_questions` VALUES (129, 'disc', '您处理细节的方式是：', '[{\"text\": \"关注大局，委托他人\", \"value\": \"D\"}, {\"text\": \"可能忽略，更关注整体\", \"value\": \"I\"}, {\"text\": \"认真对待，确保准确\", \"value\": \"S\"}, {\"text\": \"极度重视，追求完美\", \"value\": \"C\"}]', NULL, NULL, 19, 1, NULL, 1770881509, 1770881509);
INSERT INTO `mbti_questions` VALUES (130, 'disc', '您对规则的态度是：', '[{\"text\": \"规则是用来打破的\", \"value\": \"D\"}, {\"text\": \"灵活运用，不拘泥于规则\", \"value\": \"I\"}, {\"text\": \"遵守规则，维护秩序\", \"value\": \"S\"}, {\"text\": \"严格遵守，确保合规\", \"value\": \"C\"}]', NULL, NULL, 20, 1, NULL, 1770881509, 1770881509);
