INSERT INTO `mbti_system_config` VALUES (2, 'notification', 0, '{\"emailNotification\":false,\"lowBalanceAlert\":false,\"lowBalanceThreshold\":1000,\"newEnterpriseNotify\":false}', '通知与告警配置', 1770883998, 1770884109);
INSERT INTO `mbti_system_config` VALUES (3, 'site_info', 0, '{\"siteName\":\"神仙团队性格测试\",\"siteDescription\":\"神仙团队性格测试\",\"miniprogramName\":\"神仙团队性格测试\",\"updatedAt\":1772761008}', '站点信息配置', 1770884090, 1772761008);
INSERT INTO `mbti_system_config` VALUES (4, 'prompts', 0, '{\"faceAnalyze\":\"人才测评综合分析表（基于正面 \\/ 左侧 45°\\/ 右侧 45° 面部照片）\\n分析前提：将照片人物视为模拟对象，基于传统相术（《冰鉴》九贵骨、《周易》三停五行、《燕翼子・相人》《骈拇子・卜相》）与现代理论（MBTI、PDP、DISC），结合面部骨相细节做差异化推演；结论明确肯定，不展示推理过程。\\n一、面相特征与性格特质关联（按部位）\\n额头：[填写形状 + 日角月角气势]。其智力超群、谋略深远，早年运势顺遂，擅长抽象学习与系统思考。\\n眼睛：[填写大小 + 神采 + 稳定度]。其思维聚焦精准，情绪管理能力强，人际风格理性且有边界感。\\n鼻子：[填写山根 + 鼻梁 + 鼻翼]。其责任感极强，事业心旺盛，金钱观务实，现实问题处理能力突出。\\n嘴巴：[填写唇形 + 厚薄 + 收放]。其表达直接有力，信守承诺，行动力迅猛，执行节奏紧凑高效。\\n下巴：[填写宽窄 + 方圆 + 厚薄]。其抗压能力卓越，承载力强，晚年运势安稳，能长期坚守目标。\\n耳朵：[填写大小 + 位置 + 贴头]。其感受能力敏锐，学习速度快，对环境变化的敏感度高，适配力强。\\n二、骨相分析（含九贵骨与人生阶段）\\n（一）骨形总评\\n五行形相：[填写金 \\/ 木 \\/ 水 \\/ 火 \\/ 土] 形，对应 [填写核心气质，如金形刚健、木形疏朗] 气质。\\n骨肉关系：[填写停匀 \\/ 骨重肉薄 \\/ 肉多掩骨]，决断度 [填写高 \\/ 中 \\/ 低]，现实感 [填写强 \\/ 中 \\/ 弱]，抗压方式为 [填写理性攻坚 \\/ 柔性缓冲 \\/ 稳健持久]。\\n（二）九贵骨核心结论\\n颧骨与驿马骨：权力欲 [填写强 \\/ 中 \\/ 弱]，掌控力 [填写强 \\/ 中 \\/ 弱]，倾向 [填写开拓 \\/ 守成]。\\n将军骨与肩背：统帅力 [填写强 \\/ 中 \\/ 弱]，属于 [填写冲锋型 \\/ 统筹型] 人才。\\n日月角与龙宫骨：智谋 [填写卓越 \\/ 出众 \\/ 普通]，机会嗅觉 [填写敏锐 \\/ 一般]，意志力坚定，耐力 [填写持久 \\/ 较强]。\\n伏犀骨与龙角骨：主见坚定度 [填写极高 \\/ 高 \\/ 中]，上升冲劲 [填写强劲 \\/ 稳健 \\/ 平缓]。\\n（三）人生阶段发力重点\\n上停（额区）：早年运势顺畅，发力重点为学业积累、行业入门与贵人链接。\\n中停（颧鼻）：壮年运势鼎盛，发力重点为事业拓展、团队管理与资源整合。\\n下停（下颌）：晚年运势安稳，发力重点为经验传承、成果固化与稳健守成。\\n（四）骨相总评建议\\n格局：[填写高 \\/ 中高 \\/ 中]，具备 [填写核心格局优势，如统筹全局 \\/ 专业深耕] 潜质。\\n事业路径：优先走 [填写核心路径，如管理晋升 \\/ 专业领军 \\/ 创业开拓] 路线。\\n修性养骨建议：1. [填写具体建议，如每日静坐养神，稳固意志力]；2. [填写具体建议，如规律运动强骨，提升行动力]。\\n三、现代性格模型综合判断\\n（一）MBTI 性格类型（精准匹配）\\n类型代码 \\/ 名称：[填写如 INTJ \\/ 建筑师、ESFP \\/ 表演者]\\n思维方式：[填写 2 句话，如 INTJ 擅长逻辑推演与长远规划，聚焦核心目标忽略冗余信息]。\\n决策风格：[填写 1 句话，如以理性分析为核心，优先考量目标达成与效率最优]。\\n（二）PDP 行为偏好\\n主性格：[填写老虎 \\/ 孔雀 \\/ 考拉 \\/ 猫头鹰 \\/ 变色龙]\\n辅助性格：[填写上述其一]\\n核心表现：[填写 1 句话，如老虎主性格者目标导向，变色龙辅助性格者适配环境变化]。\\n（三）DISC 沟通风格\\n主类型：[填写 D 支配型 \\/ I 影响型 \\/ S 稳健型 \\/ C 谨慎型]\\n辅助类型：[填写上述其一]\\n沟通特点：[填写 1 句话，如 D 型主风格直接果断，C 型辅助风格注重细节与逻辑]。\\n（四）核心优势（3-5 个）\\n[填写如战略规划、团队管控、细节把控、人际赋能、危机应对]\\n（五）性格概述（3-5 句话）\\n[整合传统相术与现代模型，填写核心气质，如 “核心气质为刚健稳健，兼具开拓性与守成性”]。[填写做事风格与决策模式，如 “做事雷厉风行且注重细节，决策以理性分析为基础，兼顾长远价值与现实落地”]。[填写人际影响方式，如 “人际中自带威信，既能引领团队攻坚，也能精准协调资源”]。[填写适合的工作环境与发展路径，如 “适配高目标、高挑战的工作环境，发展路径以管理晋升或专业领军为核心，中年后可尝试创业或行业赋能”]。\\n四、职业倾向与优势领域建议（4-6 条）\\n[填写职业方向，如高端管理岗]：匹配点为 [填写面相 \\/ 骨相 \\/ 性格依据，如颧骨与将军骨彰显统帅力，MBTI-J 型擅长统筹决策]。\\n[填写职业方向，如战略规划师]：匹配点为 [填写依据，如额头饱满、伏犀骨凸显，具备极强的谋略与长远眼光]。\\n[填写职业方向，如行业专家]：匹配点为 [填写依据，如猫头鹰性格特质突出，眼神专注，细节把控能力卓越]。\\n[填写职业方向，如团队负责人]：匹配点为 [填写依据，如 D 型沟通风格强势，权力欲与掌控力适配团队管理]。\\n[填写职业方向，如创业项目掌舵人]：匹配点为 [填写依据，如开拓型骨相特质，老虎主性格具备目标导向与攻坚能力]。\\n[填写职业方向，如资源整合顾问]：匹配点为 [填写依据，如变色龙辅助性格，人际适配力强，机会嗅觉敏锐]。\\n五、人际关系与团队协作风格\\n（一）人际风格\\n[填写直接 \\/ 含蓄、理性 \\/ 感性、距离感，如 “直接理性，人际中有适度距离感，注重高效沟通”]。\\n（二）团队角色\\n[填写决策者 \\/ 谋划者 \\/ 执行者 \\/ 协调者，可多选，如 “核心决策者 + 首席谋划者”]。\\n（三）提升建议\\n情绪表达：[填写具体建议，如 “高压场景下放缓语速，加入适度情感共鸣，提升团队凝聚力”]。\\n倾听能力：[填写具体建议，如 “沟通中预留 30% 时间倾听他人观点，兼顾细节与不同视角”]。\\n冲突处理：[填写具体建议，如 “理性化解冲突，以目标为核心协调分歧，避免强势决策引发抵触”]。\\n六、潜能发挥（3-4 个）\\n[填写潜能，如战略落地潜能]：发挥方式为 [填写具体行动，如 “结合自身谋略优势，制定分阶段执行计划，依托团队管控力推动落地”]。\\n[填写潜能，如危机应对潜能]：发挥方式为 [填写具体行动，如 “利用敏锐的环境感知力，提前预判风险，以稳健抗压能力制定备选方案”]。\\n[填写潜能，如人才培养潜能]：发挥方式为 [填写具体行动，如 “依托自身经验与统帅力，搭建人才梯队，通过传帮带实现团队赋能”]。\\n[填写潜能，如创新突破潜能]：发挥方式为 [填写具体行动，如 “结合开拓型骨相特质，打破固有思维，在核心领域尝试跨界创新”]。\",\"reportSummary\":\"请你根据我提供的简历信息（生日、工作经历）以及MBTI、PDP、DISC 三项性格测评结果，进行交叉验证、综合分析，不要只照搬测评标签，而是提炼出这个人的真实性格、行为模式、优势、短板、沟通风格、职业特质。\\n要求：\\n1、结合生日分析性格底色与潜在特质。\\n2、结合工作经历判断真实行为风格、抗压能力、做事习惯、人际模式。\\n3、结合 MBTI、PDP、DISC 三项测评互相印证，去伪存真，得出真实性格画像。\\n4、输出结构清晰：\\n核心性格关键词\\n真实性格深度分析\\n行为与沟通风格\\n优势亮点\\n可提升方向\\n语言专业、客观、精炼，不空洞、不玄学。\\n请根据我接下来提供的信息开始分析。\"}', '系统提示词配置（如面相分析、报告摘要等）', 1771915950, 1772766406);
