INSERT INTO `mbti_system_config` VALUES (7, 'poster_config', 5, '{\"bgColor\":\"#ffffff\",\"bgImage\":\"https:\\/\\/karuosiyujzk.oss-cn-shenzhen.aliyuncs.com\\/mbti\\/20260305\\/img_69a93009e76ba4.00229379.png\",\"elements\":[{\"id\":\"el_1772695569798_1\",\"type\":\"nickname\",\"x\":113,\"y\":359,\"w\":150,\"h\":36,\"fontSize\":16,\"color\":\"rgb(255, 0, 0)\",\"bold\":false,\"align\":\"center\"},{\"id\":\"el_1772695592453_2\",\"type\":\"avatar\",\"x\":54,\"y\":333,\"w\":80,\"h\":80,\"shape\":\"circle\"},{\"id\":\"el_1772695597637_3\",\"type\":\"qrcode\",\"x\":127,\"y\":490,\"w\":120,\"h\":120},{\"id\":\"el_1772695600813_4\",\"type\":\"mbti\",\"x\":13,\"y\":153,\"w\":80,\"h\":32,\"content\":\"INTJ\",\"fontSize\":16,\"color\":\"#6366f1\",\"bold\":true,\"align\":\"center\"},{\"id\":\"el_1772695603591_5\",\"type\":\"pdp\",\"x\":19,\"y\":196,\"w\":80,\"h\":32,\"content\":\"猫头鹰\",\"fontSize\":16,\"color\":\"#10b981\",\"bold\":true,\"align\":\"center\"},{\"id\":\"el_1772695607589_6\",\"type\":\"disc\",\"x\":18,\"y\":233,\"w\":80,\"h\":32,\"content\":\"C型\",\"fontSize\":16,\"color\":\"#f43f5e\",\"bold\":true,\"align\":\"center\"}]}', '分销海报可视化配置（企业）', 1772695611, 1772695611);
