INSERT INTO `mbti_test_results` VALUES (30, 1, 'face', '{\"pdp\": {\"primary\": \"猫头鹰\", \"secondary\": \"\"}, \"disc\": {\"primary\": \"C\", \"secondary\": \"\"}, \"mbti\": {\"type\": \"INFJ\", \"title\": \"提倡者\"}, \"overview\": \"气质安静理性，内敛却有主见，善于思考与规划，适合深度研究与长期项目推进。\", \"photoUrls\": [\"https://karuosiyujzk.oss-cn-shenzhen.aliyuncs.com/mbti/20260224/img_699d6169ddb7b6.33742752.jpeg\", \"https://karuosiyujzk.oss-cn-shenzhen.aliyuncs.com/mbti/20260224/img_699d6169ddb7b6.33742752.jpeg\", \"https://karuosiyujzk.oss-cn-shenzhen.aliyuncs.com/mbti/20260224/img_699d6169ddb7b6.33742752.jpeg\"], \"boneAnalysis\": \"整体偏木水形，相骨清秀不臃，骨感适中偏文弱，重心在上停与中停，更重思考谋划而非强势进攻。\", \"faceAnalysis\": \"额头较宽平，眼神安定含蓄，鼻梁秀直，嘴唇柔和收敛，下颌略尖，下停偏弱显思维感性细腻。\", \"personalitySummary\": \"性格安静理性，有同理心与洞察力，重视个人边界与独立空间，做事稳妥细腻，擅长在幕后规划与支持他人。\"}', NULL, NULL, 0, 0, NULL, NULL, 1772172961, 1772172961, NULL, 'personal');
